import os
import hashlib
import tempfile
import traceback
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import numpy as np
from datetime import datetime
import json
import subprocess
import sys

app = Flask(__name__)

UPLOAD_FOLDER = 'models'
ALLOWED_EXTENSIONS = {'pkl', 'pickle'}
MAX_FILE_SIZE = 100 * 1024 * 1024  # 100MB
SAFE_MODULES = {
    'numpy',
    'sklearn',
    'pandas',
    'scipy'
}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)

app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE

models_registry = {}


class RestrictedUnpickler:
    """Secure unpickler that restricts allowed modules"""
    
    ALLOWED_MODULES = {
        'numpy.core.multiarray',
        'numpy',
        'numpy.dtype',
        'numpy.ndarray',
        'sklearn.tree._tree',
        'sklearn.tree._classes',
        'sklearn.ensemble._forest',
        'sklearn.linear_model._base',
        'sklearn.svm._classes',
        'sklearn.naive_bayes',
        'pandas.core.frame',
        'pandas.core.series',
        'scipy.sparse._csr',
    }
    
    @classmethod
    def restricted_loads(cls, data):
        """Load pickle data with restrictions"""
        import pickle
        import io
        
        class SafeUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                full_path = f"{module}.{name}"
                
                # Check if module is in allowed list
                if module not in cls.ALLOWED_MODULES and full_path not in cls.ALLOWED_MODULES:
                    raise pickle.UnpicklingError(
                        f"Attempted to load forbidden module: {module}.{name}"
                    )
                
                # Additional check for dangerous builtins
                if module == 'builtins' or module == '__builtin__':
                    if name not in ['object', 'type', 'list', 'dict', 'tuple', 'set', 'frozenset']:
                        raise pickle.UnpicklingError(
                            f"Attempted to load forbidden builtin: {name}"
                        )
                
                return super().find_class(module, name)
        
        return SafeUnpickler(io.BytesIO(data)).load()


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def validate_model_file(file_path):
    """Validate model file before loading"""
    
    # Check file size
    file_size = os.path.getsize(file_path)
    if file_size > MAX_FILE_SIZE:
        return False, "File size exceeds maximum allowed size"
    
    # Read file content
    with open(file_path, 'rb') as f:
        content = f.read()
    
    # Check for suspicious patterns
    suspicious_patterns = [
        b'__reduce__',
        b'__setstate__',
        b'eval',
        b'exec',
        b'compile',
        b'os.system',
        b'subprocess',
        b'__import__',
        b'open(',
    ]
    
    content_lower = content.lower()
    for pattern in suspicious_patterns:
        if pattern.lower() in content_lower:
            return False, f"Suspicious pattern detected: {pattern.decode('utf-8', errors='ignore')}"
    
    return True, "Valid"


def load_model_safely(file_path):
    """Load model with security restrictions"""
    try:
        # Validate file first
        is_valid, message = validate_model_file(file_path)
        if not is_valid:
            raise ValueError(f"Model validation failed: {message}")
        
        # Load with restricted unpickler
        with open(file_path, 'rb') as f:
            model_data = f.read()
        
        model = RestrictedUnpickler.restricted_loads(model_data)
        
        # Verify model has predict method
        if not hasattr(model, 'predict'):
            raise ValueError("Loaded object does not have a 'predict' method")
        
        return model
    
    except Exception as e:
        raise ValueError(f"Failed to load model: {str(e)}")


@app.route('/upload', methods=['POST'])
def upload_model():
    """Upload and register a new model"""
    
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if not allowed_file(file.filename):
        return jsonify({'error': 'Invalid file type. Only .pkl and .pickle files allowed'}), 400
    
    # Get model name from request
    model_name = request.form.get('model_name', '')
    if not model_name or not model_name.replace('_', '').replace('-', '').isalnum():
        return jsonify({'error': 'Invalid model name. Use alphanumeric characters, hyphens, and underscores only'}), 400
    
    # Get tenant ID for multi-tenancy
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    if not tenant_id.replace('_', '').replace('-', '').isalnum():
        return jsonify({'error': 'Invalid tenant ID'}), 400
    
    try:
        # Create tenant-specific directory
        tenant_dir = os.path.join(UPLOAD_FOLDER, tenant_id)
        os.makedirs(tenant_dir, exist_ok=True)
        
        # Secure filename
        filename = secure_filename(file.filename)
        
        # Generate unique filename with hash
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        file_hash = hashlib.sha256(f"{tenant_id}_{model_name}_{timestamp}".encode()).hexdigest()[:8]
        unique_filename = f"{model_name}_{timestamp}_{file_hash}.pkl"
        
        file_path = os.path.join(tenant_dir, unique_filename)
        
        # Save file temporarily
        temp_path = file_path + '.tmp'
        file.save(temp_path)
        
        # Load and validate model
        try:
            model = load_model_safely(temp_path)
            
            # Move to permanent location
            os.rename(temp_path, file_path)
            
            # Register model
            model_id = f"{tenant_id}:{model_name}"
            models_registry[model_id] = {
                'model': model,
                'path': file_path,
                'tenant_id': tenant_id,
                'model_name': model_name,
                'uploaded_at': datetime.now().isoformat(),
                'filename': unique_filename
            }
            
            return jsonify({
                'message': 'Model uploaded successfully',
                'model_id': model_id,
                'model_name': model_name,
                'tenant_id': tenant_id
            }), 201
        
        except Exception as e:
            # Clean up temp file
            if os.path.exists(temp_path):
                os.remove(temp_path)
            raise e
    
    except Exception as e:
        return jsonify({'error': f'Failed to upload model: {str(e)}'}), 400


@app.route('/predict/<model_name>', methods=['POST'])
def predict(model_name):
    """Make predictions using uploaded model"""
    
    # Get tenant ID
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    if not tenant_id.replace('_', '').replace('-', '').isalnum():
        return jsonify({'error': 'Invalid tenant ID'}), 400
    
    model_id = f"{tenant_id}:{model_name}"
    
    if model_id not in models_registry:
        return jsonify({'error': 'Model not found'}), 404
    
    try:
        # Get input data
        data = request.get_json()
        
        if not data or 'input' not in data:
            return jsonify({'error': 'No input data provided'}), 400
        
        # Convert input to numpy array
        input_data = np.array(data['input'])
        
        # Validate input size
        if input_data.size > 100000:
            return jsonify({'error': 'Input data too large'}), 400
        
        # Get model
        model = models_registry[model_id]['model']
        
        # Make prediction in isolated environment
        prediction = model.predict(input_data)
        
        # Convert prediction to list for JSON serialization
        if isinstance(prediction, np.ndarray):
            prediction = prediction.tolist()
        
        return jsonify({
            'prediction': prediction,
            'model_id': model_id,
            'model_name': model_name
        }), 200
    
    except Exception as e:
        return jsonify({'error': f'Prediction failed: {str(e)}'}), 500


@app.route('/models', methods=['GET'])
def list_models():
    """List all models for a tenant"""
    
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    if not tenant_id.replace('_', '').replace('-', '').isalnum():
        return jsonify({'error': 'Invalid tenant ID'}), 400
    
    tenant_models = []
    for model_id, model_info in models_registry.items():
        if model_info['tenant_id'] == tenant_id:
            tenant_models.append({
                'model_id': model_id,
                'model_name': model_info['model_name'],
                'uploaded_at': model_info['uploaded_at'],
                'filename': model_info['filename']
            })
    
    return jsonify({'models': tenant_models}), 200


@app.route('/models/<model_name>', methods=['DELETE'])
def delete_model(model_name):
    """Delete a model"""
    
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    if not tenant_id.replace('_', '').replace('-', '').isalnum():
        return jsonify({'error': 'Invalid tenant ID'}), 400
    
    model_id = f"{tenant_id}:{model_name}"
    
    if model_id not in models_registry:
        return jsonify({'error': 'Model not found'}), 404
    
    try:
        # Get model info
        model_info = models_registry[model_id]
        
        # Delete file
        if os.path.exists(model_info['path']):
            os.remove(model_info['path'])
        
        # Remove from registry
        del models_registry[model_id]
        
        return jsonify({'message': 'Model deleted successfully'}), 200
    
    except Exception as e:
        return jsonify({'error': f'Failed to delete model: {str(e)}'}), 500


@app.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    return jsonify({'status': 'healthy', 'models_count': len(models_registry)}), 200


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)